 11→struct TabRootView: View {
 12→    @Environment(AppRouter.self) private var router
 13→    @Environment(WorkoutSessionStore.self) private var sessionStore
 14→    @Environment(\.dependencyResolver) private var resolver
 15→
 16→    @State private var isMaintenanceMode = false
 17→    @State private var isForceUpdateRequired = false
 18→
 19→    var body: some View {
 20→        @Bindable var routerBinding = router
 21→        TabView(selection: $routerBinding.selectedTab) {
 22→            tabView(for: .home) {
 23→                HomeView(resolver: resolver)
 24→            }
 25→
 26→            tabView(for: .workout) {
 27→                WorkoutTabView(resolver: resolver)
 28→            }
 29→
 30→            tabView(for: .fitorb) {
 31→                AIChatView(resolver: resolver)
 32→            }
 33→
 34→            tabView(for: .activity) {
 35→                ActivityTabView(resolver: resolver)
 36→            }
 37→
 38→            tabView(for: .profile) {
 39→                ProfileProView()
 40→            }
 41→        }
 42→        .task {
 43→            await checkOperationalFlags()
 44→        }
 45→        .overlay {
 46→            if isMaintenanceMode {
 47→                MaintenanceOverlayView()
 48→            }
 49→        }
 50→        .fullScreenCover(isPresented: $isForceUpdateRequired) {
 51→            ForceUpdateView()
 52→        }
 53→    }
 54→
 55→    private func checkOperationalFlags() async {
 56→        guard let featureFlags = resolver.resolve(FeatureFlagChecking.self) else { return }
 57→        try? await featureFlags.refreshFlags()
 58→        isMaintenanceMode = await featureFlags.isFeatureEnabled(.maintenanceModeEnabled)
 59→        isForceUpdateRequired = await featureFlags.isFeatureEnabled(.forceUpdateEnabled)
 60→    }
 61→
 62→    private func tabView(for tab: AppTab, @ViewBuilder content: () -> some View) -> some View {
 63→        NavigationStack(path: pathBinding(for: tab)) {
 64→            content()
 65→                .navigationDestination(for: AppRoute.self) { route in
 66→                    routeDestination(for: route)
 67→                }
 68→        }
 69→        .tabItem {
 70→            // Icon-only tab items (no labels)
 71→            Image(systemName: tab.systemImage)
 72→        }
 73→        .tag(tab)
 74→    }
 75→
 76→    private func pathBinding(for tab: AppTab) -> Binding<NavigationPath> {
 77→        Binding(
 78→            get: { router.tabPaths[tab] ?? NavigationPath() },
 79→            set: { router.tabPaths[tab] = $0 }
 80→        )
 81→    }
 82→
 83→    @ViewBuilder
 84→    private func routeDestination(for route: AppRoute) -> some View {
 85→        switch route {
 86→        case .onboarding:
 87→            OnboardingFlowView(resolver: resolver, isEditing: false) {
 88→                // Pop da tab atual (pode ser home ou profile)
 89→                router.pop(on: router.selectedTab)
 90→            }
 91→        case .editProfile:
 92→            OnboardingFlowView(resolver: resolver, isEditing: true) {
 93→                // Pop da tab atual
 94→                router.pop(on: router.selectedTab)
 95→            }
 96→        case .setup:
 97→            PlaceholderView(
 98→                title: "Setup Inicial",
 99→                message: "Stepper com 6 perguntas será implementado aqui."
100→            )
101→        case .workoutPlan:
102→            WorkoutPlanView()
103→        case .exerciseDetail:
104→            WorkoutExerciseDetailView()
105→        case .workoutExecution:
106→            WorkoutExecutionView()
107→        case .workoutExercisePreview(let prescription):
108→            WorkoutExercisePreviewView(prescription: prescription)
109→        case .workoutSummary:
110→            WorkoutCompletionView()
111→        case .paywall:
112→            if let repo = resolver.resolve(EntitlementRepository.self) as? StoreKitEntitlementRepository {
113→                OptimizedPaywallView(storeService: repo.service) {
114→                    // On purchase success, generate workout
115→                    if let planId = sessionStore.plan?.id {
116→                        router.pop(on: .home) // Pop paywall
117→                        router.push(.workoutPlan(planId), on: .home)
118→                    } else {
119→                        router.pop(on: .home)
120→                    }
121→                } onDismiss: {
122→                    router.pop(on: .home)
123→                }
124→            } else {
125→                PlaceholderView(
126→                    title: "Paywall Pro",
127→                    message: "Erro ao carregar paywall."
128→                )
129→            }
130→        case .programDetail(let programId):
131→            ProgramDetailView(programId: programId, resolver: resolver)
132→        case .programWorkoutDetail(let workout):
133→            ProgramWorkoutDetailView(workout: workout, resolver: resolver)
134→        case .libraryWorkoutDetail(let workoutId):
135→            LibraryDetailView(workoutId: workoutId, resolver: resolver)
136→        case .programExerciseDetail(let prescription):
137→            LibraryExerciseDetailView(prescription: prescription)
138→        case .apiKeySettings:
139→            APIKeySettingsView()
140→        case .healthKitSettings:
141→            HealthKitConnectionView(resolver: resolver)
142→        case .privacySettings:
143→            PrivacySettingsView(resolver: resolver)
144→        case .authentication(let inviteContext):
145→            AuthenticationView(resolver: resolver, inviteContext: inviteContext) {
146→                // After authentication, pop back and stay on current tab
147→                router.pop(on: router.selectedTab)
148→            }
149→        case .groupInvite(let groupId):
150→            JoinGroupView(groupId: groupId, resolver: resolver) {
151→                // After joining, refresh activity tab (where challenges are shown)
152→                router.select(tab: .activity)
153→            }
154→        case .notifications:
155→            NotificationsView(resolver: resolver)
156→        case .customWorkouts:
157→            CustomWorkoutTemplatesView(resolver: resolver)
158→        case .customWorkoutBuilder(let templateId):
159→            if let saveUseCase = resolver.resolve(SaveCustomWorkoutUseCase.self) {
160→                let exerciseService = resolver.resolve((any ExerciseServiceProtocol).self)
161→                let viewModel = CustomWorkoutBuilderViewModel(
162→                    saveUseCase: saveUseCase,
163→                    existingTemplateId: templateId,
164→                    exerciseService: exerciseService
165→                )
166→                CustomWorkoutBuilderView(viewModel: viewModel)
167→            } else {
168→                PlaceholderView(
169→                    title: "Custom Workout",
170→                    message: "Unable to load workout builder."
171→                )
172→            }
173→        case .trainerDashboard:
174→            PersonalTrainerView(resolver: resolver, initialTab: .today)
175→        case .trainerChat:
176→            PersonalTrainerView(resolver: resolver, initialTab: .chat)
177→        case .personalTrainer:
178→            PersonalTrainerView(resolver: resolver)
179→        case .trainerSearch:
180→            let viewModel = PersonalTrainerViewModel(resolver: resolver)
181→            TrainerSearchView(viewModel: viewModel)
182→        case .cmsWorkoutDetail(let workoutId):
183→            CMSWorkoutDetailView(workoutId: workoutId, resolver: resolver)
184→        case .cmsWorkoutFeedback(let workoutId):
185→            CMSWorkoutFeedbackView(workoutId: workoutId, resolver: resolver)
186→        case .aiChat:
187→            AIChatView(resolver: resolver)
188→        case .socialFeed:
189→            if let feedRepo = resolver.resolve(FeedRepository.self),
190→               let authRepo = resolver.resolve(AuthenticationRepository.self),
191→               let deleteUseCase = resolver.resolve(DeleteFeedPostUseCase.self) {
192→                SocialFeedView(
193→                    viewModel: SocialFeedViewModel(
194→                        feedRepository: feedRepo,
195→                        authRepository: authRepo,
196→                        deleteFeedPostUseCase: deleteUseCase
197→                    )
198→                )
199→            } else {
200→                PlaceholderView(
201→                    title: "Feed Social",
202→                    message: "Erro ao carregar o feed."
203→                )
204→            }
205→        }
206→    }
207→}
