 12→/// Segments available in the Activity tab.
 13→enum ActivitySegment: String, CaseIterable {
 14→    case feed = "Feed"
 15→    case history = "Histórico"
 16→    case challenges = "Desafios"
 17→    case stats = "Stats"
 18→}
 19→
 20→/// Main view for the Activity tab.
 21→struct ActivityTabView: View {
 22→    let resolver: Resolver
 23→
 24→    @State private var selectedSegment: ActivitySegment = .history
 25→    @State private var isSocialFeedEnabled = false
 26→
 27→    private var availableSegments: [ActivitySegment] {
 28→        ActivitySegment.allCases.filter { segment in
 29→            segment != .feed || isSocialFeedEnabled
 30→        }
 31→    }
 32→
 33→    var body: some View {
 34→        VStack(spacing: 0) {
 35→            // Segmented Control
 36→            segmentedControl
 37→                .padding(.horizontal, FitTodaySpacing.md)
 38→                .padding(.vertical, FitTodaySpacing.sm)
 39→
 40→            // Content
 41→            TabView(selection: $selectedSegment) {
 42→                if isSocialFeedEnabled {
 43→                    feedTab
 44→                        .tag(ActivitySegment.feed)
 45→                }
 46→
 47→                WorkoutHistoryView(resolver: resolver)
 48→                    .tag(ActivitySegment.history)
 49→
 50→                ChallengesFullListView(resolver: resolver)
 51→                    .tag(ActivitySegment.challenges)
 52→
 53→                ActivityStatsView(resolver: resolver)
 54→                    .tag(ActivitySegment.stats)
 55→            }
 56→            .tabViewStyle(.page(indexDisplayMode: .never))
 57→        }
 58→        .background(FitTodayColor.background)
 59→        .navigationTitle("Atividade")
 60→        .navigationBarTitleDisplayMode(.large)
 61→        .task {
 62→            guard let featureFlags = resolver.resolve(FeatureFlagChecking.self) else { return }
 63→            isSocialFeedEnabled = await featureFlags.isFeatureEnabled(.socialFeedEnabled)
 64→        }
 65→    }
 66→
 67→    // MARK: - Feed Tab
 68→
 69→    @ViewBuilder
 70→    private var feedTab: some View {
 71→        if let feedRepo = resolver.resolve(FeedRepository.self),
 72→           let authRepo = resolver.resolve(AuthenticationRepository.self),
 73→           let deleteUseCase = resolver.resolve(DeleteFeedPostUseCase.self) {
 74→            SocialFeedView(
 75→                viewModel: SocialFeedViewModel(
 76→                    feedRepository: feedRepo,
 77→                    authRepository: authRepo,
 78→                    deleteFeedPostUseCase: deleteUseCase
 79→                )
 80→            )
 81→        } else {
 82→            VStack(spacing: FitTodaySpacing.md) {
 83→                Image(systemName: "person.3.fill")
 84→                    .font(.system(size: 48))
 85→                    .foregroundStyle(FitTodayColor.textSecondary)
 86→                Text("Entre em um grupo para ver o feed")
 87→                    .font(.subheadline)
 88→                    .foregroundStyle(FitTodayColor.textSecondary)
 89→            }
 90→            .frame(maxWidth: .infinity, maxHeight: .infinity)
 91→        }
 92→    }
 93→
 94→    // MARK: - Segmented Control
 95→
 96→    private var segmentedControl: some View {
 97→        HStack(spacing: FitTodaySpacing.xs) {
 98→            ForEach(availableSegments, id: \.self) { segment in
 99→                Button {
100→                    withAnimation(.easeInOut(duration: 0.2)) {
101→                        selectedSegment = segment
102→                    }
103→                } label: {
104→                    Text(segment.rawValue)
105→                        .font(FitTodayFont.ui(size: 14, weight: selectedSegment == segment ? .bold : .medium))
106→                        .foregroundStyle(selectedSegment == segment ? FitTodayColor.textPrimary : FitTodayColor.textSecondary)
107→                        .frame(maxWidth: .infinity)
108→                        .padding(.vertical, FitTodaySpacing.sm)
109→                        .background(
110→                            RoundedRectangle(cornerRadius: FitTodayRadius.sm)
111→                                .fill(selectedSegment == segment ? FitTodayColor.brandPrimary.opacity(0.2) : Color.clear)
112→                        )
113→                }
114→                .buttonStyle(.plain)
115→            }
116→        }
117→        .padding(FitTodaySpacing.xs)
118→        .background(
119→            RoundedRectangle(cornerRadius: FitTodayRadius.md)
120→                .fill(FitTodayColor.surface)
121→        )
122→    }
123→}
