 12→final class SocialFeedViewModel {
 13→    // MARK: - State
 14→
 15→    private(set) var posts: [FeedPost] = []
 16→    private(set) var isLoading = false
 17→    var errorMessage: String?
 18→
 19→    // MARK: - Dependencies
 20→
 21→    private let feedRepository: FeedRepository
 22→    private let authRepository: AuthenticationRepository
 23→    private let deleteFeedPostUseCase: DeleteFeedPostUseCase
 24→    private var currentUserId: String?
 25→    private var currentGroupId: String?
 26→    nonisolated(unsafe) private var observeTask: Task<Void, Never>?
 27→
 28→    // MARK: - Init
 29→
 30→    init(
 31→        feedRepository: FeedRepository,
 32→        authRepository: AuthenticationRepository,
 33→        deleteFeedPostUseCase: DeleteFeedPostUseCase
 34→    ) {
 35→        self.feedRepository = feedRepository
 36→        self.authRepository = authRepository
 37→        self.deleteFeedPostUseCase = deleteFeedPostUseCase
 38→    }
 39→
 40→    // MARK: - Load
 41→
 42→    func loadFeed() async {
 43→        isLoading = true
 44→        defer { isLoading = false }
 45→
 46→        do {
 47→            guard let user = try await authRepository.currentUser() else {
 48→                errorMessage = FeedError.notAuthenticated.localizedDescription
 49→                return
 50→            }
 51→            currentUserId = user.id
 52→            currentGroupId = user.currentGroupId
 53→
 54→            guard let groupId = user.currentGroupId else {
 55→                errorMessage = FeedError.notInGroup.localizedDescription
 56→                return
 57→            }
 58→
 59→            posts = try await feedRepository.getPosts(groupId: groupId, limit: 50, after: nil)
 60→        } catch {
 61→            errorMessage = error.localizedDescription
 62→        }
 63→    }
 64→
 65→    // MARK: - Real-time Observation
 66→
 67→    func startObserving() {
 68→        observeTask?.cancel()
 69→        observeTask = Task { [weak self] in
 70→            guard let self else { return }
 71→
 72→            do {
 73→                guard let user = try await authRepository.currentUser(),
 74→                      let groupId = user.currentGroupId else { return }
 75→                currentUserId = user.id
 76→                currentGroupId = groupId
 77→
 78→                for await newPosts in feedRepository.observePosts(groupId: groupId) {
 79→                    self.posts = newPosts
 80→                    self.isLoading = false
 81→                }
 82→            } catch {
 83→                self.errorMessage = error.localizedDescription
 84→            }
 85→        }
 86→        isLoading = true
 87→    }
 88→
 89→    nonisolated func stopObserving() {
 90→        observeTask?.cancel()
 91→        observeTask = nil
 92→    }
 93→
 94→    // MARK: - Actions
 95→
 96→    func toggleLike(postId: String) async {
 97→        guard let userId = currentUserId else { return }
 98→
 99→        do {
100→            let isLiked = try await feedRepository.toggleLike(postId: postId, userId: userId)
101→
102→            // Optimistic update
103→            if let index = posts.firstIndex(where: { $0.id == postId }) {
104→                var post = posts[index]
105→                if isLiked {
106→                    post.likedBy.append(userId)
107→                    post.likeCount += 1
108→                } else {
109→                    post.likedBy.removeAll { $0 == userId }
110→                    post.likeCount = max(0, post.likeCount - 1)
111→                }
112→                posts[index] = post
113→            }
114→        } catch {
115→            errorMessage = error.localizedDescription
116→        }
117→    }
118→
119→    func deletePost(_ postId: String) async {
120→        do {
121→            try await deleteFeedPostUseCase.execute(postId: postId)
122→            posts.removeAll { $0.id == postId }
123→        } catch {
124→            errorMessage = error.localizedDescription
125→        }
126→    }
127→
128→    func isCurrentUser(_ authorId: String) -> Bool {
129→        currentUserId == authorId
130→    }
131→
132→    func isPostLiked(_ post: FeedPost) -> Bool {
133→        guard let userId = currentUserId else { return false }
134→        return post.isLiked(by: userId)
135→    }
136→
137→    deinit {
138→        stopObserving()
139→    }
140→}
