//
//  ActivityTabView.swift
//  FitToday
//
//  Main tab view for activity tracking, history, and challenges.
//

import SwiftUI
import Charts
import Swinject

/// Segments available in the Activity tab.
enum ActivitySegment: String, CaseIterable {
    case feed = "Feed"
    case history = "Histórico"
    case challenges = "Desafios"
    case stats = "Stats"
}

/// Main view for the Activity tab.
struct ActivityTabView: View {
    let resolver: Resolver

    @State private var selectedSegment: ActivitySegment = .history
    @State private var isSocialFeedEnabled = false

    private var availableSegments: [ActivitySegment] {
        ActivitySegment.allCases.filter { segment in
            segment != .feed || isSocialFeedEnabled
        }
    }

    var body: some View {
        VStack(spacing: 0) {
            // Segmented Control
            segmentedControl
                .padding(.horizontal, FitTodaySpacing.md)
                .padding(.vertical, FitTodaySpacing.sm)

            // Content
            TabView(selection: $selectedSegment) {
                if isSocialFeedEnabled {
                    feedTab
                        .tag(ActivitySegment.feed)
                }

                WorkoutHistoryView(resolver: resolver)
                    .tag(ActivitySegment.history)

                ChallengesFullListView(resolver: resolver)
                    .tag(ActivitySegment.challenges)

                ActivityStatsView(resolver: resolver)
                    .tag(ActivitySegment.stats)
            }
            .tabViewStyle(.page(indexDisplayMode: .never))
        }
        .background(FitTodayColor.background)
        .navigationTitle("Atividade")
        .navigationBarTitleDisplayMode(.large)
        .task {
            guard let featureFlags = resolver.resolve(FeatureFlagChecking.self) else { return }
            isSocialFeedEnabled = await featureFlags.isFeatureEnabled(.socialFeedEnabled)
        }
    }

    // MARK: - Feed Tab

    @ViewBuilder
    private var feedTab: some View {
        if let feedRepo = resolver.resolve(FeedRepository.self),
           let authRepo = resolver.resolve(AuthenticationRepository.self),
           let deleteUseCase = resolver.resolve(DeleteFeedPostUseCase.self) {
            SocialFeedView(
                viewModel: SocialFeedViewModel(
                    feedRepository: feedRepo,
                    authRepository: authRepo,
                    deleteFeedPostUseCase: deleteUseCase
                )
            )
        } else {
            VStack(spacing: FitTodaySpacing.md) {
                Image(systemName: "person.3.fill")
                    .font(.system(size: 48))
                    .foregroundStyle(FitTodayColor.textSecondary)
                Text("Entre em um grupo para ver o feed")
                    .font(.subheadline)
                    .foregroundStyle(FitTodayColor.textSecondary)
            }
            .frame(maxWidth: .infinity, maxHeight: .infinity)
        }
    }

    // MARK: - Segmented Control

    private var segmentedControl: some View {
        HStack(spacing: FitTodaySpacing.xs) {
            ForEach(availableSegments, id: \.self) { segment in
                Button {
                    withAnimation(.easeInOut(duration: 0.2)) {
                        selectedSegment = segment
                    }
                } label: {
                    Text(segment.rawValue)
                        .font(FitTodayFont.ui(size: 14, weight: selectedSegment == segment ? .bold : .medium))
                        .foregroundStyle(selectedSegment == segment ? FitTodayColor.textPrimary : FitTodayColor.textSecondary)
                        .frame(maxWidth: .infinity)
                        .padding(.vertical, FitTodaySpacing.sm)
                        .background(
                            RoundedRectangle(cornerRadius: FitTodayRadius.sm)
                                .fill(selectedSegment == segment ? FitTodayColor.brandPrimary.opacity(0.2) : Color.clear)
                        )
                }
                .buttonStyle(.plain)
            }
        }
        .padding(FitTodaySpacing.xs)
        .background(
            RoundedRectangle(cornerRadius: FitTodayRadius.md)
                .fill(FitTodayColor.surface)
        )
    }
}

// MARK: - Workout History View

struct WorkoutHistoryView: View {
    let resolver: Resolver

    @State private var selectedDate = Date()
    @State private var workouts: [WorkoutHistoryEntry] = []
    @State private var isLoading = true
    @State private var listAppeared = false

    private var repository: WorkoutHistoryRepository? {
        resolver.resolve(WorkoutHistoryRepository.self)
    }

    private var workoutDays: Set<DateComponents> {
        let calendar = Calendar.current
        return Set(workouts.compactMap { entry in
            calendar.dateComponents([.year, .month, .day], from: entry.date)
        })
    }

    var body: some View {
        ScrollView {
            VStack(spacing: FitTodaySpacing.lg) {
                // Calendar
                calendarSection

                // Workout List
                workoutListSection
            }
            .padding(FitTodaySpacing.md)
        }
        .scrollIndicators(.hidden)
        .task {
            await loadWorkouts()
        }
    }

    // MARK: - Calendar Section

    private var calendarSection: some View {
        VStack(alignment: .leading, spacing: FitTodaySpacing.sm) {
            Text("Calendário")
                .font(FitTodayFont.ui(size: 17, weight: .bold))
                .foregroundStyle(FitTodayColor.textPrimary)

            // Simple month calendar
            MonthCalendarView(
                selectedDate: $selectedDate,
                highlightedDays: workoutDays
            )
        }
    }

    // MARK: - Workout List Section

    private var workoutListSection: some View {
        VStack(alignment: .leading, spacing: FitTodaySpacing.sm) {
            Text("Treinos Recentes")
                .font(FitTodayFont.ui(size: 17, weight: .bold))
                .foregroundStyle(FitTodayColor.textPrimary)

            if isLoading {
                loadingView
            } else if workouts.isEmpty {
                emptyStateView
            } else {
                LazyVStack(spacing: FitTodaySpacing.sm) {
                    ForEach(Array(workouts.enumerated()), id: \.element.id) { index, entry in
                        WorkoutEntryCard(entry: entry)
                            .opacity(listAppeared ? 1 : 0)
                            .offset(y: listAppeared ? 0 : 16)
                            .animation(
                                .easeOut(duration: 0.3).delay(Double(index) * 0.05),
                                value: listAppeared
                            )
                    }
                }
                .onAppear {
                    listAppeared = false
                    withAnimation { listAppeared = true }
                }
            }
        }
    }

    private var loadingView: some View {
        VStack(spacing: FitTodaySpacing.sm) {
            ForEach(0..<4, id: \.self) { _ in
                RoundedRectangle(cornerRadius: FitTodayRadius.md)
                    .fill(FitTodayColor.surface)
                    .frame(height: 80)
                    .shimmer()
            }
        }
    }

    private var emptyStateView: some View {
        VStack(spacing: FitTodaySpacing.md) {
            Image(systemName: "figure.run.circle")
                .font(.system(size: 48))
                .foregroundStyle(FitTodayColor.textTertiary)

            Text("Nenhum treino ainda")
                .font(FitTodayFont.ui(size: 17, weight: .semiBold))
                .foregroundStyle(FitTodayColor.textPrimary)

            Text("Complete seu primeiro treino para ver seu histórico")
                .font(FitTodayFont.ui(size: 14, weight: .medium))
                .foregroundStyle(FitTodayColor.textSecondary)
                .multilineTextAlignment(.center)
        }
        .frame(maxWidth: .infinity)
        .padding(FitTodaySpacing.xl)
    }

    // MARK: - Data Loading

    private func loadWorkouts() async {
        guard let repository else {
            isLoading = false
            return
        }

        do {
            let entries = try await repository.listEntries(limit: 20, offset: 0)
            workouts = entries
        } catch {
            workouts = []
        }
        isLoading = false
    }
}

// MARK: - Month Calendar View

struct MonthCalendarView: View {
    @Binding var selectedDate: Date
    let highlightedDays: Set<DateComponents>

    // BUG 7 FIX: use Monday-first week to match startOfWeek used by weekly stats.
    private let calendar: Calendar = {
        var cal = Calendar.current
        cal.firstWeekday = 2 // Monday = 2
        return cal
    }()
    // Mon, Tue, Wed, Thu, Fri, Sat, Sun
    private let daysOfWeek = ["S", "T", "Q", "Q", "S", "S", "D"]

    private var monthDays: [Date?] {
        let interval = calendar.dateInterval(of: .month, for: selectedDate)!
        let firstDay = interval.start
        // weekday in Calendar.current is 1=Sun … 7=Sat.
        // Convert to Monday-first column index: Mon=0 … Sun=6.
        let firstWeekday = Calendar.current.component(.weekday, from: firstDay)
        let mondayFirstOffset = (firstWeekday - 2 + 7) % 7
        let daysInMonth = calendar.range(of: .day, in: .month, for: selectedDate)!.count

        var days: [Date?] = Array(repeating: nil, count: mondayFirstOffset)

        for day in 1...daysInMonth {
            if let date = calendar.date(byAdding: .day, value: day - 1, to: firstDay) {
                days.append(date)
            }
        }

        // Pad to complete last week
        while days.count % 7 != 0 {
            days.append(nil)
        }

        return days
    }

    var body: some View {
        VStack(spacing: FitTodaySpacing.sm) {
            // Month navigation
            HStack {
                Button {
                    withAnimation {
                        selectedDate = calendar.date(byAdding: .month, value: -1, to: selectedDate)!
                    }
                } label: {
                    Image(systemName: "chevron.left")
                        .foregroundStyle(FitTodayColor.textSecondary)
                }

                Spacer()

                Text(selectedDate, format: .dateTime.month(.wide).year())
                    .font(FitTodayFont.ui(size: 16, weight: .semiBold))
                    .foregroundStyle(FitTodayColor.textPrimary)

                Spacer()

                Button {
                    withAnimation {
                        selectedDate = calendar.date(byAdding: .month, value: 1, to: selectedDate)!
                    }
                } label: {
                    Image(systemName: "chevron.right")
                        .foregroundStyle(FitTodayColor.textSecondary)
                }
            }
            .padding(.horizontal, FitTodaySpacing.sm)

            // Days of week header
            HStack(spacing: 0) {
                ForEach(daysOfWeek, id: \.self) { day in
                    Text(day)
                        .font(FitTodayFont.ui(size: 12, weight: .medium))
                        .foregroundStyle(FitTodayColor.textTertiary)
                        .frame(maxWidth: .infinity)
                }
            }

            // Calendar grid
            LazyVGrid(columns: Array(repeating: GridItem(.flexible()), count: 7), spacing: FitTodaySpacing.xs) {
                ForEach(Array(monthDays.enumerated()), id: \.offset) { _, date in
                    if let date {
                        DayCell(
                            date: date,
                            isHighlighted: isHighlighted(date),
                            isSelected: calendar.isDate(date, inSameDayAs: selectedDate),
                            isToday: calendar.isDateInToday(date)
                        ) {
                            selectedDate = date
                        }
                    } else {
                        Color.clear
                            .frame(width: 36, height: 36)
                    }
                }
            }
        }
        .padding(FitTodaySpacing.md)
        .background(
            RoundedRectangle(cornerRadius: FitTodayRadius.md)
                .fill(FitTodayColor.surface)
        )
    }

    private func isHighlighted(_ date: Date) -> Bool {
        let components = calendar.dateComponents([.year, .month, .day], from: date)
        return highlightedDays.contains(components)
    }
}

// MARK: - Day Cell

struct DayCell: View {
    let date: Date
    let isHighlighted: Bool
    let isSelected: Bool
    let isToday: Bool
    let action: () -> Void

    private let calendar = Calendar.current

    var body: some View {
        Button(action: action) {
            Text("\(calendar.component(.day, from: date))")
                .font(FitTodayFont.ui(size: 14, weight: isSelected || isToday ? .bold : .medium))
                .foregroundStyle(foregroundColor)
                .frame(width: 36, height: 36)
                .background(backgroundColor)
                .clipShape(Circle())
                .overlay(
                    Circle()
                        .stroke(isToday && !isSelected ? FitTodayColor.brandPrimary : Color.clear, lineWidth: 2)
                )
        }
        .buttonStyle(.plain)
    }

    private var foregroundColor: Color {
        if isSelected {
            return .white
        } else if isHighlighted {
            return FitTodayColor.brandPrimary
        } else {
            return FitTodayColor.textPrimary
        }
    }

    private var backgroundColor: Color {
        if isSelected {
            return FitTodayColor.brandPrimary
        } else if isHighlighted {
            return FitTodayColor.brandPrimary.opacity(0.15)
        } else {
            return Color.clear
        }
    }
}

